package be.schaubroeck.lpb.rkm.rekenmotor.manueletussenkomst;

import be.schaubroeck.lpb.rkm.artikel.dto.AardKodeExtensieDTO;
import be.schaubroeck.lpb.rkm.artikel.dto.OpdrachtDTO;
import be.schaubroeck.lpb.rkm.rekenmotor.dto.ManueleTussenkomstDTO;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.ControleAgenda;
import be.schaubroeck.lpb.tools.ManueleTussenkomst;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.RekenHoofd;
import be.schaubroeck.lpb.tools.RekenLijn;
import be.schaubroeck.lpb.tools.api.dto.CodeEnumDTO;
import be.schaubroeck.lpb.tools.caching.ake.AardKodeExtensieFacade;
import be.schaubroeck.lpb.tools.enumtypes.ManueleTussenkomstFunctie;
import be.schaubroeck.lpb.tools.enumtypes.RekenBedragType;
import be.schaubroeck.lpb.tools.exception.MessageException;
import be.schaubroeck.lpb.tools.service.ManueleTussenkomstService;
import be.schaubroeck.lpb.tools.service.OpdrachtService;
import be.schaubroeck.lpb.tools.service.RekenResultatenService;
import be.schaubroeck.temporal.interval.Day;
import lombok.AllArgsConstructor;
import lombok.Builder;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.util.Arrays;
import java.util.List;
import java.util.stream.Collectors;

@AllArgsConstructor
@Builder
public class AutoTussenkomstBeslagOpLoon {

    private Admin admin;
    private OpdrachtService opdrachtService;
    private RekenResultatenService rekenResultatenService;
    private ManueleTussenkomstService manueleTussenkomstService;
    private AardKodeExtensieFacade aardKodeExtensieFacade;


    public ManueleTussenkomstDTO genereer(ControleAgenda agenda) {
        Opdracht opdracht = opdrachtService.getByPersoonOpdrachtNrActualFree(admin, agenda.getPersoon().getId(), agenda.getOpdrachtNummer(), "persoon{persoonSlices}");
        List<RekenLijn> rekenlijnen = findRekenLijnenBeslagOpLoon(opdracht, agenda);
        AardKodeExtensie aardKodeExtensie = getAardKodeExtensie(rekenlijnen);
        LocalDate datum = agenda.getEindDatum().compareTo(opdracht.getEindDatum()) < 0 ? agenda.getEindDatum() : opdracht.getEindDatum();
        BigDecimal amount = sommeerNettoBedragen(rekenlijnen);
        List<ManueleTussenkomst> existing = findExistingTussenkomsten(opdracht, datum, aardKodeExtensie);

        if (existing.isEmpty()) {
            return createManueleTussenkomstDTO(opdracht, aardKodeExtensie, datum, amount);
        } else if (existing.size() == 1) {
            return modifyExistingManueleTussenkomstDTO(opdracht, aardKodeExtensie, existing.get(0));
        } else {
            throw new MessageException("Er zijn meerdere bestaande manuele tussenkomsten voor deze aard kode extensie!");
        }
    }

    private List<RekenLijn> findRekenLijnenBeslagOpLoon(Opdracht opdracht, ControleAgenda agenda) {
        List<Opdracht> opdrachten = Arrays.asList(opdracht);
        List<RekenHoofd> rekenhoofden =
                rekenResultatenService.findByOpdrachtenBegindatum(admin, opdrachten, agenda.getBeginDatum(), "rekenLijnen{aardKodeExtensie, rekenBedragen}");

        return rekenhoofden.stream()
                .flatMap(o -> o.getRekenLijnen().stream())
                .filter(r -> r.getAardKodeExtensie().getAard() == 4 && (r.getAardKodeExtensie().getCode() == 5101 || r.getAardKodeExtensie().getCode() == 5102))
                .collect(Collectors.toList());
    }

    private List<ManueleTussenkomst> findExistingTussenkomsten(Opdracht opdracht, LocalDate datum, AardKodeExtensie aardKodeExtensie) {
        List<Opdracht> opdrachten = Arrays.asList(opdracht);
        return manueleTussenkomstService.findByOpdrachtenPeriode(admin, opdrachten, new Day(datum))
                .stream()
                .filter(o -> o.getAardKodeExtensie().getId().compareTo(aardKodeExtensie.getId()) == 0)
                .collect(Collectors.toList());
    }

    private BigDecimal sommeerNettoBedragen(List<RekenLijn> rekenlijnen) {
        return rekenlijnen
                .stream()
                .flatMap(o -> o.getRekenBedragen().stream().filter(r -> r.getBedragType() == RekenBedragType.NETTO))
                .map(o -> o.getBedrag().getAmount())
                .reduce(BigDecimal.ZERO, BigDecimal::add);
    }

    private AardKodeExtensie getAardKodeExtensie(List<RekenLijn> rekenlijnen) {
        List<Integer> aardKodeExtIdList = rekenlijnen.stream().map(rekenLijn -> rekenLijn.getAardKodeExtensie().getId()).distinct().collect(Collectors.toList());
        if (aardKodeExtIdList.isEmpty()) {
            throw new MessageException("Er zijn geen aard kode extensie gevonden voor beslag!");
        } else if (aardKodeExtIdList.size() > 1) {
            throw new MessageException("Er zijn meerdere aard kode extensies gevonden voor beslag!");
        }
        return aardKodeExtensieFacade.getById(aardKodeExtIdList.get(0));
    }

    private ManueleTussenkomstDTO modifyExistingManueleTussenkomstDTO(Opdracht opdracht, AardKodeExtensie aardKodeExtensie, ManueleTussenkomst existing) {
        ManueleTussenkomstDTO dto = new ManueleTussenkomstDTO(existing);
        dto.setFromControleAgenda(Boolean.TRUE);
        dto.setOpdracht(new OpdrachtDTO(opdracht, false));
        dto.setAardKodeExtensie(new AardKodeExtensieDTO(aardKodeExtensie));
        return dto;
    }

    private ManueleTussenkomstDTO createManueleTussenkomstDTO(Opdracht opdracht, AardKodeExtensie aardKodeExtensie, LocalDate datum, BigDecimal amount) {
        ManueleTussenkomstDTO dto = new ManueleTussenkomstDTO();
        dto.setOpdracht(new OpdrachtDTO(opdracht, false));
        dto.setAardKodeExtensie(new AardKodeExtensieDTO(aardKodeExtensie));
        dto.setBedragType(new CodeEnumDTO(RekenBedragType.NETTO));
        dto.setDatum(datum);
        dto.setFunctie(new CodeEnumDTO(ManueleTussenkomstFunctie.ACTIEF_PLUS));
        dto.setRegimeBv(new CodeEnumDTO(aardKodeExtensie.getRegimeBv()));
        dto.setFromControleAgenda(Boolean.TRUE);
        dto.setBedrag(amount);
        return dto;
    }

}
